SELECT ROUND(
   ( ( (SELECT overall_rating FROM Player_Attributes pa WHERE pa.player_api_id = (SELECT player_api_id FROM Player WHERE player_name='Landon Donovan') AND pa.date='2013/7/12')
     - (SELECT overall_rating FROM Player_Attributes pa WHERE pa.player_api_id = (SELECT player_api_id FROM Player WHERE player_name='Jordan Bowery') AND pa.date='2013/7/12')
   ) * 100.0
   / (SELECT overall_rating FROM Player_Attributes pa WHERE pa.player_api_id = (SELECT player_api_id FROM Player WHERE player_name='Landon Donovan') AND pa.date='2013/7/12')
) , 2) AS percentage;	----- bird -----	european_football_2

